PROCEDURE HitOrMiss(image A, fgSE B1, bgSE B2)
 result ← zeros(size(A))
 origin ← getOrigin(B1)

 // Erode with foreground SE
 fgMatch ← Erode(A, B1)

 // Create complement image
 Acomp ← 1 - A

 // Erode complement with background SE
 bgMatch ← Erode(Acomp, B2)

 // Hit occurs where both matches coincide
 FOR each pixel (i,j) DO
 result[i,j] ← fgMatch[i,j] AND bgMatch[i,j]
 END FOR

 RETURN result
END PROCEDURE

// Note: For proper operation, B1 and B2 must be disjoint
// and their union should form a complete SE
